// renderReply (streaming display)
// ---------------------------------------------------------------------------
export interface RenderResult {
  content: string;
  parseMode: "HTML" | undefined;
}

export function renderReply(
  session: ChatSession,
  done: boolean,
  parsers: ScheduleParsers,
): RenderResult {
  const toolLines = toolPrefixLines(session);
  const tools = toolLines.length ? toolLines.join("\n") + "\n\n" : "";
  const cursor = done ? "" : " ▍";
  const emptyFallback = () => {
    if (!done) return session.thinkingBuffer ? "" : "Thinking…";
    const n = session.toolTimeline.length;
    return n > 0 ? `(no text yet — ${n} tool call${n === 1 ? "" : "s"} so far)` : "(no response)";
  };

  // Show thinking progress during streaming (hide when done)
  let thinkingBlock = "";
  if (!done && session.thinkingBuffer) {
    // Show last ~200 chars of thinking as blockquote
    const t = session.thinkingBuffer;
    const preview = t.length > 200 ? "…" + t.slice(-200) : t;
    thinkingBlock = "💭 " + preview.split("\n").join("\n> ") + "\n\n";
  }

  const raw = session.buffer || emptyFallback();
  const stripped = transformReplyTokens(raw, parsers).text;
  let body = stripped || emptyFallback();
  // 扣除 tools/thinkingBlock/cursor 佔用的長度，避免拼接後超過 Telegram 4096 上限
  const overhead = tools.length + thinkingBlock.length + cursor.length;
  const bodyBudget = Math.max(TG_MAX - overhead, 200);
  if (body.length > bodyBudget) {
    body = "…" + body.slice(-bodyBudget);
  }

  const plain = tools + thinkingBlock + body + cursor;
  const { html } = markdownToHtml(plain);
  // HTML 膨脹超過 Telegram 4096 上限時 fallback 到純文字（markdown budget 已 ≤3900，純文字必定安全）
  if (html.length > 4096) {
    return { content: plain, parseMode: undefined };
  }
  return { content: html, parseMode: "HTML" };
}

let throttledSnapshotLogged = false;
let turnHitRateLimit = false;
let turnFinalized = false;

const editNow = async () => {
  if (!placeholder && !useDraftMode) return;
  if (rateLimitedUntil() > Date.now()) {
    turnHitRateLimit = true;
    if (!throttledSnapshotLogged) {
      throttledSnapshotLogged = true;
      const snapshot = (session.buffer || "").trim();
      const preview = snapshot.length > 800
        ? snapshot.slice(0, 800) + `…[+${snapshot.length - 800} chars]`
        : snapshot;
      console.warn(
        `[rate-limit] chat ${chatId} streaming paused; current buffer (${snapshot.length} chars):\n---\n${preview || "(empty)"}\n---`
      );
    }
    return;
  }
  const { content, parseMode } = renderReply(session, false, scheduleParsers);
  if (content === lastRendered) return;
  lastRendered = content;
  lastEditAt = Date.now();
  try {
    // Draft path：全量替換 draft 內容
    if (useDraftMode && draftId) {
      const ok = await trySendDraft(ctx.api, chatId, draftId, content, config.tgRichStreamEnabled);
      if (ok) return;
      // Draft TTL 過期或 API 拒絕 → 降級為 placeholder 模式
      if (!placeholder) {
        try {
          placeholder = await ctx.api.sendMessage(chatId, content,
            parseMode ? { parse_mode: parseMode } : {});
        } catch { /* 降級也失敗（仍在 rate limit），下次 editNow 重試 */ }
        useDraftMode = false;
        draftId = 0;
        return;
      }
    }
    if (placeholder) {
      if (config.tgRichStreamEnabled) {
        const richEdited = await tryEditRichMessageDraft(ctx.api, chatId, placeholder.message_id, content);
        if (richEdited) return;
      }
      await ctx.api.editMessageText(chatId, placeholder.message_id, content,
        parseMode ? { parse_mode: parseMode } : {});
    }
