402→// ---------------------------------------------------------------------------
403→export interface RenderResult {
404→  content: string;
405→  parseMode: "HTML" | undefined;
406→}
407→
408→export function renderReply(
409→  session: ChatSession,
410→  done: boolean,
411→  parsers: ScheduleParsers,
412→): RenderResult {
413→  const toolLines = toolPrefixLines(session);
414→  const tools = toolLines.length ? toolLines.join("\n") + "\n\n" : "";
415→  const cursor = done ? "" : " ▍";
416→  const emptyFallback = () => {
417→    if (!done) return session.thinkingBuffer ? "" : "Thinking…";
418→    const n = session.toolTimeline.length;
419→    return n > 0 ? `(no text yet — ${n} tool call${n === 1 ? "" : "s"} so far)` : "(no response)";
420→  };
421→
422→  // Show thinking progress during streaming (hide when done)
423→  let thinkingBlock = "";
424→  if (!done && session.thinkingBuffer) {
425→    // Show last ~200 chars of thinking as blockquote
426→    const t = session.thinkingBuffer;
427→    const preview = t.length > 200 ? "…" + t.slice(-200) : t;
428→    thinkingBlock = "💭 " + preview.split("\n").join("\n> ") + "\n\n";
429→  }
430→
431→  const raw = session.buffer || emptyFallback();
432→  const stripped = transformReplyTokens(raw, parsers).text;
433→  let body = stripped || emptyFallback();
434→  // 扣除 tools/thinkingBlock/cursor 佔用的長度，避免拼接後超過 Telegram 4096 上限
435→  const overhead = tools.length + thinkingBlock.length + cursor.length;
436→  const bodyBudget = Math.max(TG_MAX - overhead, 200);
437→  if (body.length > bodyBudget) {
438→    body = "…" + body.slice(-bodyBudget);
439→  }
440→
441→  const plain = tools + thinkingBlock + body + cursor;
442→  const { html } = markdownToHtml(plain);
443→  // HTML 膨脹超過 Telegram 4096 上限時 fallback 到純文字（markdown budget 已 ≤3900，純文字必定安全）
444→  if (html.length > 4096) {
445→    return { content: plain, parseMode: undefined };
446→  }
447→  return { content: html, parseMode: "HTML" };
448→}
