let rateLimitedUntil = 0;
let lastRateLimitSecs = 0;
let rateLimitChatId: number | undefined;
let rateLimitRecoveryTimer: NodeJS.Timeout | null = null;
const pendingMessages: Array<{ chatId: number; text: string }> = [];
const rateLimitRecoveryListeners: Set<RecoveryListener> = new Set();

async function flushPendingMessages() {
  const startCount = pendingMessages.length;
  let flushed = 0;
  while (pendingMessages.length > 0) {
    if (rateLimitedUntil > Date.now()) {
      console.warn(
        `[rate-limit] flush paused mid-way: flushed ${flushed}/${startCount}, ${pendingMessages.length} remain`,
      );
      return;
    }
    const { chatId, text } = pendingMessages.shift()!;
    try {
      await bot.api.sendMessage(chatId, text);
      flushed++;
      console.log(`[rate-limit] flushed queued message → chat ${chatId} (${flushed}/${startCount})`);
    } catch (err) {
      console.error("[rate-limit] replay failed, requeueing:", err);
      pendingMessages.unshift({ chatId, text });
      return;
    }
    await new Promise<void>((r) => setTimeout(r, 1100));
  }
  if (startCount > 0) {
    console.log(`[rate-limit] flush complete: ${flushed}/${startCount} delivered`);
  }
}

bot.api.config.use(async (prev, method, payload, signal) => {
  const res = await prev(method, payload, signal);
  const retryAfter = (res as any)?.parameters?.retry_after;
  if (typeof retryAfter === "number" && retryAfter > 0) {
    const until = Date.now() + retryAfter * 1000;
    const chatId = Number((payload as any)?.chat_id);
    if (Number.isFinite(chatId)) rateLimitChatId = chatId;
    if (until > rateLimitedUntil) {
      rateLimitedUntil = until;
      if (retryAfter > lastRateLimitSecs) lastRateLimitSecs = retryAfter;
      console.warn(
        `[rate-limit] Telegram 429: retry_after=${retryAfter}s chat=${
          Number.isFinite(chatId) ? chatId : "?"
        } method=${method} — pausing edits until ${new Date(until).toISOString()}`
      );
      if (rateLimitRecoveryTimer) {
        clearTimeout(rateLimitRecoveryTimer);
        rateLimitRecoveryTimer = null;
      }
      const waitMs = until - Date.now() + 500;
      rateLimitRecoveryTimer = setTimeout(async () => {
        rateLimitRecoveryTimer = null;
        const peak = lastRateLimitSecs;
        const target = rateLimitChatId;
        lastRateLimitSecs = 0;
        rateLimitedUntil = 0;
        console.log(
          `[rate-limit] recovered after ${peak}s — flushing ${pendingMessages.length} pending message(s)`
        );
        if (target === undefined) return;

