/**
 * run-prompt.ts — Core agent prompt execution logic.
 * Extracted from index.ts (P3 split).
 */
import path from "node:path";
import { readFileSync, writeFileSync, existsSync } from "node:fs";
import { Bot, Context, InlineKeyboard } from "grammy";
import { config } from "./config.js";
import { SessionManager, ChatSession, isRelayDelegatePlaceholderGoal, toolPrefixLines } from "./sessionManager.js";
import {
  transform as transformReplyTokens,
} from "./observerTransformer.js";
import * as goalStore from "./goalStore.js";
import * as usageStore from "./usageStore.js";
import { logEvent } from "./event-log.js";
import { STICKER_MAP } from "./stickerMap.js";
import { sendRelay, sendRelayFile, sendRelayDelegate, sendRelayResult, DELEGATE_PREFIX } from "./relay.js";
import type { DelegatePayload, ResultPayload } from "./relay.js";
import { isEmbedModelReady, embedText, cosineSim } from "./embed-router.js";
import { detectSkillDir } from "./memory.js";
import { isLocalSpecialist, dispatchToSpecialist, dispatchParallel, startProxy, endProxy, promptProxy, getProxyStats, buildProxySummary } from "./specialist.js";
import type { ParallelTask } from "./specialist.js";
import { appendRoutingLog } from "./routing-log.js";
import { verifySpecialistOutput, buildRetryPrompt } from "./verifier.js";
import { synthesizeDualPath, buildFusionContext } from "./self-fusion.js";
import { saveArtifact } from "./artifact.js";
import { isDuplicateResult } from "./reply-dedup.js";
import { petState, petEmit } from "./pet-server.js";
import { registerTask, completeTask } from "./status-store.js";
import {
  maskCodeRegions, buildAskKeyboard, sendFilesByPaths,
  splitForTelegram, renderReply, askRegistry, TG_MAX,
  type ScheduleParsers,
} from "./telegram-ui.js";
import {
  extractMemoryTokensFromProxy, stripMemoryTokens, saveDelegationContext,
  loadDelegationContext, notifyRelayOwner, getRelayLoopGuard, upsertRelayTask,
  addRelayTaskOutput,
} from "./commands/relay.js";
import { scheduleParsers, parseDuration, parseAbsoluteTime } from "./commands/schedule.js";
import { estimateTokens, pct } from "./commands/misc.js";
import { formatRelative } from "./utils.js";
import { autoWikilink } from "./wiki-retrieval.js";
import { evaluateForAutoSave, recordAutoSaveCandidate } from "./query-auto-save.js";
import { parseRecurrence, computeNextRunAt, formatRecurrence } from "./recurrence.js";
import { ScheduleStore } from "./schedule-store.js";
import { Scheduler } from "./scheduler.js";
import type { ContinuationContext } from "./types.js";
import { tryEditRichMessageDraft, trySendDraft, trySendRichMessage } from "./telegram-rich-renderer.js";
import { quotaHint } from "./provider/quota-error.js";

// ─── Types ───────────────────────────────────────────────────────────────────

/** Same shape as ContinuationContext; re-aliased so the runPrompt body
 * can distinguish "plan scheduled for next turn" from "we're currently
 * running one" at the type level. */
type ContinuationPlan = ContinuationContext;

export type RunPromptMode =
  | { kind: "user"; replyHeader?: string }
  | { kind: "continuation"; context: ContinuationContext }
  | { kind: "meta"; silent?: boolean }
  | { kind: "relay"; replyTo: string };

// ─── Sticker auto-selection ──────────────────────────────────────────────────

const EMOTION_REPRS: Record<string, string> = {
  hello: "打招呼 你好 嗨 早安 晚安 greeting",
  happy: "開心 太好了 成功 完成了 恭喜 great",
  thanks: "謝謝 感謝 thank you 不客氣",
  sorry: "抱歉 對不起 不好意思 sorry",
  agree: "同意 沒問題 好的 了解 ok sure",
  good: "做得好 讚 很棒 nice well done",
  clap: "恭喜 太厲害了 完美 bravo",
  love: "喜歡 愛 太棒了 超讚",
  sad: "可惜 遺憾 不幸 unfortunately",
  shock: "驚訝 天啊 沒想到 wow unexpected",
  ok: "收到 了解 知道了 acknowledged",
};
const STICKER_AUTO_THRESHOLD = 0.65;
const STICKER_AUTO_MAX_REPLY_LEN = 150;
let emotionVectors: Map<string, Float32Array> | null = null;

export async function autoSelectSticker(reply: string): Promise<string | null> {
  if (reply.length > STICKER_AUTO_MAX_REPLY_LEN || reply.length < 5) return null;
  if (!emotionVectors) {
    emotionVectors = new Map();
    for (const [emotion, repr] of Object.entries(EMOTION_REPRS)) {
      const vec = await embedText(repr);
      if (vec) emotionVectors.set(emotion, vec);
    }
  }
  const queryVec = await embedText(reply);
  if (!queryVec) return null;
  let best = "";
  let bestScore = 0;
  for (const [emotion, vec] of emotionVectors) {
    const score = cosineSim(queryVec, vec);
    if (score > bestScore) { bestScore = score; best = emotion; }
  }
  return bestScore >= STICKER_AUTO_THRESHOLD ? best : null;
}

// ─── Continuation timer ──────────────────────────────────────────────────────

const GOAL_CONTINUATION_DELAY_MS = 500;
const pendingContinuations = new Map<number, NodeJS.Timeout>();

export function cancelPendingContinuation(chatId: number): void {
  const h = pendingContinuations.get(chatId);
  if (h) {
    clearTimeout(h);
    pendingContinuations.delete(chatId);
  }
}

// ─── Deps interface — mutable state that lives in index.ts ───────────────────

export interface RunPromptDeps {
  bot: Bot;
  sessions: SessionManager;
  rateLimitedUntil: () => number;
  onRateLimitRecovery: (fn: () => void | Promise<void>) => () => void;
  queuePendingMessage: (chatId: number, text: string) => void;
  handleRestart: (ctx: Context, opts?: { reason?: string }) => Promise<void>;
  STREAM_EDIT_INTERVAL_MS: number;
  MEMORY_DIR: string;
  scheduler: Scheduler;
  scheduleStore: ScheduleStore;
}

let _deps: RunPromptDeps | null = null;

export function initRunPrompt(deps: RunPromptDeps): void {
  _deps = deps;
}

function deps(): RunPromptDeps {
  if (!_deps) throw new Error("runPrompt not initialized — call initRunPrompt first");
  return _deps;
}

// ─── Auto-wikilink post-processing ───────────────────────────────────────────

/** After a wiki page is written, scan it and inject [[wikilinks]] for known entities. */
function applyAutoWikilink(slug: string): void {
  const { MEMORY_DIR } = deps();
  for (const sub of ["queries", "concepts", "references", "lessons", "tasks"]) {
    const filePath = path.join(MEMORY_DIR, "wiki", sub, `${slug}.md`);
    if (existsSync(filePath)) {
      try {
        const content = readFileSync(filePath, "utf8");
        const linked = autoWikilink(content);
        if (linked !== content) {
          writeFileSync(filePath, linked, "utf8");
          console.log(`[auto-wikilink] injected links into wiki/${sub}/${slug}.md`);
        }
      } catch (err) {
        console.error(`[auto-wikilink] failed for ${slug}:`, err);
      }
      return;
    }
  }
}

// ─── Orphan turn flusher ──────────────────────────────────────────────────────
//
// Delivers agent output that arrived with NO active prompt turn — e.g. a
// Claude Code harness background sub-agent completes and re-invokes the agent
// via task-notification, producing an agent_message_chunk while runPrompt's
// request→response flush path isn't listening (see SPEC-orphan-turn-flusher).
//
// SessionManager buffers + debounces those chunks and calls this on quiescence
// (wired via sessions.onOrphanTurn in index.ts). This reuses the SAME reply
// transform (transformReplyTokens) + render/split helpers as the normal turn —
// there is deliberately NO second transform. Tokens that only make sense inside
// a live turn (GOAL_DONE / RESTART / CONTINUE / WIKI_QUERY / SKILL_PROPOSE /
// SPECIALIST_PROXY / relay*) are intentionally ignored here; user-facing tokens
// (text / SEND_FILE / ASK / SCHEDULE / STICKER) are delivered.
export async function flushOrphanTurn(session: ChatSession, rawText: string): Promise<void> {
  const { bot, rateLimitedUntil, queuePendingMessage, scheduler, scheduleStore } = deps();
  const chatId = session.chatId;

  // Dedup: skip content already delivered (e.g. same summary that also came
  // through a normal turn, or a duplicate orphan flush). Shares the 5-min
  // window used by specialist/parallel result injection.
  if (isDuplicateResult(chatId, rawText)) {
    console.log(`[orphan ${chatId}] skipped (dedup hit)`);
    return;
  }

  const ab7 = transformReplyTokens(rawText, {
    parseDuration,
    parseAbsoluteTime,
    parseRecurrence,
    computeNextRunAt,
  });

  // SCHEDULE tokens — register the same way the normal path does.
  const scheduleReceipts: string[] = [];
  for (const se of ab7.scheduleTokens) {
    try {
      const entry = await scheduleStore.add({
        chatId,
        userId: session.userId ?? chatId,
        runAt: se.runAt,
        prompt: se.prompt,
        recurrence: se.recurrence,
      });
      scheduler.arm(entry);
      const delta = formatRelative(se.runAt - Date.now());
      const recurTag = se.recurrence ? ` [${formatRecurrence(se.recurrence)}]` : "";
      scheduleReceipts.push(
        `⏰ 已排程 ${entry.id}${recurTag}，${delta} 後觸發（${new Date(se.runAt).toLocaleString()}）`,
      );
    } catch (err) {
      console.error(`[orphan ${chatId}] schedule token register failed:`, err);
    }
  }

  // Surface (but don't act on) tokens that require live-turn context.
  const ignored: string[] = [];
  if (ab7.goalDone) ignored.push("GOAL_DONE");
  if (ab7.restartToken) ignored.push("RESTART");
  if (ab7.continueToken) ignored.push("CONTINUE");
  if (ab7.wikiQuery) ignored.push("WIKI_QUERY");
  if (ab7.skillPropose) ignored.push("SKILL_PROPOSE");
  if (ab7.specialistProxy) ignored.push("SPECIALIST_PROXY");
  if (ab7.moaPlan) ignored.push("MOA_PLAN");
  if (ignored.length) {
    console.log(`[orphan ${chatId}] ignoring turn-context token(s): ${ignored.join(", ")}`);
  }

  const body = scheduleReceipts.length
    ? (ab7.text ? `${ab7.text}\n\n${scheduleReceipts.join("\n")}` : scheduleReceipts.join("\n"))
    : ab7.text;
  const askKeyboard = buildAskKeyboard(ab7.askTokens);

  // Text delivery (chunked). Rate-limit aware: queue for replay if throttled.
  if (body.trim().length > 0) {
    const chunks = splitForTelegram(body);
    for (let i = 0; i < chunks.length; i++) {
      const isLast = i === chunks.length - 1;
      const pageTag = chunks.length > 1 ? `(${i + 1}/${chunks.length})\n` : "";
      const text = pageTag + chunks[i];
      const extra = isLast && askKeyboard ? { reply_markup: askKeyboard } : undefined;
      if (rateLimitedUntil() > Date.now()) {
        queuePendingMessage(chatId, text);
        continue;
      }
      try {
        const msg = await bot.api.sendMessage(chatId, text, extra);
        if (isLast && askKeyboard && msg?.message_id !== undefined) {
          askRegistry.set(msg.message_id, ab7.askTokens);
        }
      } catch (err) {
        console.error(`[orphan ${chatId}] chunk send failed, queueing for replay:`, err);
        queuePendingMessage(chatId, text);
      }
      if (!isLast) await new Promise<void>((r) => setTimeout(r, 1100));
    }
  } else if (askKeyboard) {
    // ASK-only orphan turn (rare) — carry the keyboard on a minimal message.
    try {
      const msg = await bot.api.sendMessage(chatId, "（背景任務完成）", { reply_markup: askKeyboard });
      if (msg?.message_id !== undefined) askRegistry.set(msg.message_id, ab7.askTokens);
    } catch (err) {
      console.error(`[orphan ${chatId}] ask-only send failed:`, err);
    }
  }

  // SEND_FILE — sendFilesByPaths needs a Context-like; build a minimal shim.
  if (ab7.sendFiles.length > 0) {
    const fakeCtx = {
      chat: { id: chatId, type: "private" as const },
      replyWithPhoto: (f: unknown, extra?: unknown) => bot.api.sendPhoto(chatId, f as any, extra as any),
      replyWithDocument: (f: unknown, extra?: unknown) => bot.api.sendDocument(chatId, f as any, extra as any),
    } as unknown as Context;
    try {
      await sendFilesByPaths(fakeCtx, ab7.sendFiles);
    } catch (err) {
      console.error(`[orphan ${chatId}] sendFilesByPaths failed:`, err);
    }
  }

  // Stickers
  for (const emotion of ab7.stickerEmotions) {
    const fileId = STICKER_MAP[emotion];
    if (!fileId) continue;
    try {
      await bot.api.sendSticker(chatId, fileId);
    } catch (err) {
      console.warn(`[orphan ${chatId}] sticker ${emotion} failed — ${(err as Error).message}`);
    }
  }

  console.log(
    `[orphan ${chatId}] delivered (textChars=${body.length}, files=${ab7.sendFiles.length}, ` +
      `asks=${ab7.askTokens.length}, schedules=${scheduleReceipts.length}, stickers=${ab7.stickerEmotions.length})`,
  );
}

// ─── runPrompt ────────────────────────────────────────────────────────────────

export async function runPrompt(
  ctx: Context,
  session: ChatSession,
  text: string,
  mode: RunPromptMode = { kind: "user" },
) {
  const { bot, sessions, rateLimitedUntil, onRateLimitRecovery, queuePendingMessage,
    handleRestart, STREAM_EDIT_INTERVAL_MS, MEMORY_DIR, scheduler, scheduleStore } = deps();

  const continuationContext: ContinuationContext | undefined =
    mode.kind === "continuation" ? mode.context : undefined;
  const isMeta = mode.kind === "meta";
  const isSilentMeta = mode.kind === "meta" && mode.silent === true;
  const relayReplyTo = mode.kind === "relay" ? mode.replyTo : undefined;
  const isRelay = mode.kind === "relay";
  // Optional header prepended to the visible reply (and shown in the "Thinking…"
  // placeholder). Used e.g. by ASK button clicks to record "我選擇了：X" in the
  // reply itself, so the original button message isn't rewritten and no extra
  // message is sent. Render-only — NOT added to agent history/memory.
  const replyHeader = mode.kind === "user" ? mode.replyHeader : undefined;
  const chatId = ctx.chat!.id;

  // Guard against concurrent prompts on the same ACP session.
  if (session.inflight) {
    if (relayReplyTo) {
      sendRelay(relayReplyTo, "小X 目前上一輪還在處理中，稍後再回覆。").catch((err) =>
        console.error(`[chat ${chatId}] relay busy notice to ${relayReplyTo} failed:`, err),
      );
      notifyRelayOwner(
        bot,
        config.allowedUserIds[0] ?? 0,
        `⏳ 「${relayReplyTo}」又送來 relay 訊息，但上一輪還在處理中，已擋掉這次重複注入。`,
        `busy notice for ${relayReplyTo}`,
      );
      return;
    }
    if (isMeta) {
      console.log(`[chat ${chatId}] meta prompt queued (session inflight)`);
      session._pendingMetaQueue.push({ ctx: ctx as unknown as any, prompt: text, opts: mode as any });
      return;
    }
    await ctx.reply(
      "⏳ 上一個回合還在進行中。請等它結束，或先用 /cancel 取消。",
    );
    return;
  }
  session.inflight = true;
  sessions.resetTurn(session);
  petState("thinking");

  let continuationPlan: ContinuationPlan | null = null;
  let continueTokenFired = false;
  let pendingRestartReason: string | null = null;

  if (!continuationContext) {
    session.history.push({ role: "user", text, timestamp: Date.now() });
    // 多 session auto-naming：首則 user 訊息當預設名。fire-and-forget——
    // 寫 store 在 prompt hot path，絕不 await 阻塞；只填空名（冪等，
    // resume 後 history 歸零重複觸發無害）。
    if (config.acpSessionResume && session.activeProvider === "acp" &&
        session.history.filter((h) => h.role === "user").length === 1) {
      import("./session-registry.js")
        .then((m) => m.autoNameActive(session.chatId, text))
        .catch(() => {});
    }
  }
  session.charsIn += text.length;

  // Context Budget Warning: inject once when context reaches 70%
  let budgetWarning = "";
  if (!session._budgetWarned && config.contextWindowTokens) {
    const totalChars = session.preambleBreakdown.total + session.charsIn + session.charsOut;
    const estimatedTokens = Math.ceil(totalChars / 4);
    if (estimatedTokens > config.contextWindowTokens * 0.7) {
      session._budgetWarned = true;
      budgetWarning =
        "\n\n[⚠️ Context Budget Warning: session context has reached ~70% capacity. " +
        "Consider wrapping up the current task, using remember() to save important state, " +
        "and preparing for a <<RESTART:context budget>> if needed. " +
        "Avoid starting new multi-step tasks.]\n\n";
      console.log(`[budget] chat ${chatId} hit 70% context (${estimatedTokens}/${config.contextWindowTokens} tok)`);
    }
  }

  let promptText = text;
  if (!session.preambleInjected && session.memoryPreamble) {
    promptText = session.memoryPreamble + text;
    session.preambleInjected = true;
  }
  if (budgetWarning) {
    promptText = budgetWarning + promptText;
  }

  const replyToId = ctx.message?.message_id;
  const placeholderText = continuationContext
    ? `↻ Continuing (${continuationContext.turnIndex}/${continuationContext.maxTurns}) toward goal…`
    : replyHeader
      ? `${replyHeader}\n\nThinking…`
      : "Thinking…";
  let placeholder: { message_id: number } | undefined;
  // Draft streaming：private chat + 設定開啟時用 sendMessageDraft 取代 placeholder
  const isPrivateChat = ctx.chat?.type === "private";
  let useDraftMode = false;
  let draftId = 0;
  if (!isRelay && !isSilentMeta) {
    if (config.tgDraftEnabled && isPrivateChat) {
      draftId = Date.now() & 0x7FFFFFFF; // 正整數，非零
      const draftOk = await trySendDraft(ctx.api, chatId, draftId, "", false);
      if (draftOk) {
        useDraftMode = true;
      }
    }
    // Draft 失敗或不適用 → 走現有 placeholder
    if (!useDraftMode) {
      try {
        placeholder = await ctx.reply(placeholderText, {
          ...(replyToId ? { reply_parameters: { message_id: replyToId } } : {}),
        });
      } catch (err: any) {
        const desc = err?.description || err?.error?.description || "";
        if (replyToId && /message to be replied not found/i.test(desc)) {
          placeholder = await ctx.reply(placeholderText);
        } else {
          throw err;
        }
      }
    }
  }

  // Store placeholder msgId for optimistic cancel UI feedback
  session._placeholderMsgId = placeholder?.message_id;

  let lastEditAt = 0;
  let lastRendered = "";
  let editTimer: NodeJS.Timeout | null = null;
  let throttledSnapshotLogged = false;
  let turnHitRateLimit = false;
  let turnFinalized = false;

  const editNow = async () => {
    if (!placeholder && !useDraftMode) return;
    if (rateLimitedUntil() > Date.now()) {
      turnHitRateLimit = true;
      if (!throttledSnapshotLogged) {
        throttledSnapshotLogged = true;
        const snapshot = (session.buffer || "").trim();
        const preview = snapshot.length > 800
          ? snapshot.slice(0, 800) + `…[+${snapshot.length - 800} chars]`
          : snapshot;
        console.warn(
          `[rate-limit] chat ${chatId} streaming paused; current buffer (${snapshot.length} chars):\n---\n${preview || "(empty)"}\n---`
        );
      }
      return;
    }
    const { content, parseMode } = renderReply(session, false, scheduleParsers);
    if (content === lastRendered) return;
    lastRendered = content;
    lastEditAt = Date.now();
    try {
      // Draft path：全量替換 draft 內容
      if (useDraftMode && draftId) {
        const ok = await trySendDraft(ctx.api, chatId, draftId, content, config.tgRichStreamEnabled);
        if (ok) return;
        // Draft TTL 過期或 API 拒絕 → 降級為 placeholder 模式
        if (!placeholder) {
          try {
            placeholder = await ctx.api.sendMessage(chatId, content,
              parseMode ? { parse_mode: parseMode } : {});
          } catch { /* 降級也失敗（仍在 rate limit），下次 editNow 重試 */ }
          useDraftMode = false;
          draftId = 0;
          return;
        }
      }
      if (placeholder) {
        if (config.tgRichStreamEnabled) {
          const richEdited = await tryEditRichMessageDraft(ctx.api, chatId, placeholder.message_id, content);
          if (richEdited) return;
        }
        await ctx.api.editMessageText(chatId, placeholder.message_id, content,
          parseMode ? { parse_mode: parseMode } : {});
      }
    } catch {
      // Telegram returns 400 if content identical; ignore.
    }
  };

  const unregisterRecovery = isRelay || isSilentMeta ? () => {} : onRateLimitRecovery(() => {
    if (turnFinalized) {
      console.log(
        `[rate-limit] chat ${chatId} recovery callback suppressed — turn already finalized`
      );
      return;
    }
    throttledSnapshotLogged = false;
    console.log(
      `[rate-limit] chat ${chatId} resuming edits — pushing latest buffer (${(session.buffer || "").length} chars)`
    );
    lastRendered = "";
    return editNow();
  });

  session.onUpdate = isRelay
    ? undefined
    : () => {
        const elapsed = Date.now() - lastEditAt;
        if (elapsed >= STREAM_EDIT_INTERVAL_MS) {
          editNow();
        } else if (!editTimer) {
          editTimer = setTimeout(() => {
            editTimer = null;
            editNow();
          }, STREAM_EDIT_INTERVAL_MS - elapsed);
        }
      };


  try {
    // Self-fusion: for goal high-stakes decisions, get alternative perspective
    if (mode.kind === "user" && !isMeta) {
      const gs = await goalStore.get(config.memoryDir, chatId).catch(() => null);
      if (gs?.status === "active" && text.length > 50) {
        const decisionSignals = /\b(選|choose|pick|decide|recommend|architecture|刪除|delete|migrate|重構|refactor|方案|approach)\b/i;
        if (decisionSignals.test(text)) {
          const { trioInfer } = await import("./trio-llm.js");
          const altResp = await trioInfer(text.slice(0, 500), {
            system: "You are a contrarian advisor. Give a brief alternative perspective or risk consideration for this decision. 2-3 sentences max.",
            maxTokens: 150, temperature: 0.9, timeout: 8_000,
          });
          if (altResp.text && altResp.source !== "none") {
            const fusion = await synthesizeDualPath(text.slice(0, 200), "（主模型即將回覆）", altResp.text);
            if (fusion) {
              promptText = buildFusionContext(text.slice(0, 200), fusion) + "\n" + promptText;
            } else {
              promptText = `[Alternative perspective (${altResp.source})]\n${altResp.text}\n[End]\n\n` + promptText;
            }
          }
        }
      }
    }

    const { stopReason } = await session.client.prompt(promptText);
    if (editTimer) {
      clearTimeout(editTimer);
      editTimer = null;
    }
    turnFinalized = true;
    session._placeholderMsgId = undefined;

    if (session.buffer) {
      session.history.push({ role: "assistant", text: session.buffer, timestamp: Date.now() });
    }

    const toolLines = toolPrefixLines(session);
    const toolsPrefix = toolLines.length ? toolLines.join("\n") + "\n\n" : "";

    // Extract relay tokens before ab7 (it doesn't know them).
    const relayTokens: { target: string; text: string }[] = [];
    const relayFileTokens: { target: string; path: string }[] = [];
    const relayDelegateTokens: { target: string; payload: DelegatePayload }[] = [];
    const relayResultTokens: { target: string; payload: ResultPayload }[] = [];
    const parallelDelegateTasks: ParallelTask[] = [];
    const RELAY_RE = /<<RELAY:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
    const RELAY_FILE_RE = /<<RELAY_FILE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
    const RELAY_DELEGATE_RE = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
    const RELAY_RESULT_RE = /<<RELAY_RESULT:\s*([^|>\r\n]+?)\s*\|\s*(\{[^>\r\n]+?\})\s*>>/g;
    const PARALLEL_DELEGATE_RE = /<<PARALLEL_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
    {
      const { masked, restore } = maskCodeRegions(session.buffer);
      const stripped = masked
        .replace(RELAY_DELEGATE_RE, (_m, target: string, body: string) => {
          let p: DelegatePayload;
          try {
            p = JSON.parse(body) as DelegatePayload;
            if (!p.id && (p as any).correlationId) p.id = (p as any).correlationId;
          } catch {
            p = { id: `rd_${Date.now()}`, goal: body.trim() };
          }
          if (p.goal && !isRelayDelegatePlaceholderGoal(p.goal)) {
            relayDelegateTokens.push({ target: target.trim(), payload: p });
          }
          return "";
        })
        .replace(RELAY_RESULT_RE, (_m, target: string, json: string) => {
          try {
            const p = JSON.parse(json) as ResultPayload;
            relayResultTokens.push({ target: target.trim(), payload: p });
          } catch { /* malformed JSON — ignore */ }
          return "";
        })
        .replace(RELAY_RE, (_m, target: string, msg: string) => {
          relayTokens.push({ target: target.trim(), text: msg.trim() });
          return "";
        })
        .replace(RELAY_FILE_RE, (_m, target: string, p: string) => {
          relayFileTokens.push({ target: target.trim(), path: p.trim() });
          return "";
        })
        .replace(PARALLEL_DELEGATE_RE, (_m, taskId: string, target: string, prompt: string) => {
          parallelDelegateTasks.push({
            taskId: taskId.trim(),
            target: target.trim(),
            payload: { id: taskId.trim(), goal: prompt.trim() },
          });
          return "";
        });
      session.buffer = restore(stripped);
    }

    // Fallback: recover RELAY_DELEGATE from streaming captures
    if (relayDelegateTokens.length === 0 && session._streamingDelegates?.length) {
      const RELAY_DELEGATE_RE2 = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
      for (const raw of session._streamingDelegates) {
        RELAY_DELEGATE_RE2.lastIndex = 0;
        const m = RELAY_DELEGATE_RE2.exec(raw);
        if (m) {
          let p: DelegatePayload;
          try {
            p = JSON.parse(m[2]) as DelegatePayload;
            if (!p.id && (p as any).correlationId) p.id = (p as any).correlationId;
          } catch {
            p = { id: `rd_${Date.now()}`, goal: m[2].trim() };
          }
          if (p.goal && !isRelayDelegatePlaceholderGoal(p.goal)) {
            relayDelegateTokens.push({ target: m[1].trim(), payload: p });
          }
        }
      }
      if (relayDelegateTokens.length > 0) {
        console.log(`[chat ${chatId}] relay delegate recovered from streaming capture (${relayDelegateTokens.length} token(s))`);
      }
    }

    // <<RELAY_DONE>>
    const { masked: maskedForDone, restore: restoreDone } = maskCodeRegions(session.buffer);
    const relayDone = /<<RELAY_DONE>>/i.test(maskedForDone);
    if (relayDone) {
      session.buffer = restoreDone(maskedForDone.replace(/<<RELAY_DONE>>/gi, "").trim());
      if (relayReplyTo) getRelayLoopGuard()?.markDone(relayReplyTo);
    }

    const ab7 = transformReplyTokens(session.buffer, {
      parseDuration,
      parseAbsoluteTime,
      parseRecurrence,
      computeNextRunAt,
    });

    // SKILL_USED → usageStore
    if (ab7.skillUsages.length > 0) {
      const skillDir = detectSkillDir();
      if (!skillDir.startsWith("(")) {
        for (const u of ab7.skillUsages) {
          usageStore.markUsed(skillDir, u.name, u.reason).catch((err) => {
            console.error(`[chat ${chatId}] usageStore.markUsed(${u.name}) failed:`, err);
          });
        }
      } else {
        console.warn(`[chat ${chatId}] SKILL_USED tokens seen but SKILL_DIR unresolved: ${skillDir}`);
      }
    }


    // ─── Goal bookkeeping ─────────────────────────────────────────────────────
    let goalAchievementLine: string | null = null;
    if (isMeta) {
      // no-op: meta turns bypass all goal bookkeeping
    } else if (ab7.goalDone) {
      try {
        const wasActive = await goalStore.isActive(config.memoryDir, chatId);
        if (wasActive) {
          const s = await goalStore.markDone(config.memoryDir, chatId, ab7.goalDone.reason);
          goalAchievementLine = `\n\n✓ Goal achieved: ${s.last_reason}`;
          logEvent("goal_done", { reason: ab7.goalDone.reason, turnsUsed: s.turns_used }, { chatId, userId: ctx.from?.id });
        } else {
          console.warn(`[chat ${chatId}] GOAL_DONE ignored: no active goal (reason="${ab7.goalDone.reason}")`);
        }
      } catch (err) {
        console.error(`[chat ${chatId}] goalStore.markDone failed:`, err);
      }
    } else if (!continuationContext) {
      try {
        const gs = await goalStore.get(config.memoryDir, chatId);
        if (gs && gs.status === "active") {
          const result = await goalStore.incrementTurn(config.memoryDir, chatId, session.buffer ? session.buffer.slice(0, 200) : undefined);
          logEvent("goal_step", { turn: result.state.turns_used, maxTurns: result.state.max_turns, pausedByBudget: result.pausedByBudget }, { chatId, userId: ctx.from?.id });
          if (result.pausedByBudget) {
            const reflection = `Budget exhausted (${result.state.turns_used}/${result.state.max_turns}) without achieving goal. Last output: ${(session.buffer || "").slice(0, 200)}`;
            const retryResult = await goalStore.markReflectionRetry(config.memoryDir, chatId, reflection);
            if (retryResult.ok) {
              console.log(`[chat ${chatId}] goal reflection retry ${retryResult.state.reflection_retries}/${goalStore.GOAL_REFLECTION_MAX}`);
              continuationPlan = {
                turnIndex: 1,
                maxTurns: retryResult.state.max_turns,
                objective: retryResult.state.objective,
                lastReason: `[Reflection retry ${retryResult.state.reflection_retries}/${goalStore.GOAL_REFLECTION_MAX}] Previous attempt failed to achieve the goal. Reflect: what went wrong? Try a different approach.\n${reflection}`,
              };
            } else {
              goalAchievementLine = `\n\n⏸ Goal paused — ${result.state.turns_used}/${result.state.max_turns} turns used, ${result.state.reflection_retries}/${goalStore.GOAL_REFLECTION_MAX} retries exhausted. /goal resume 續跑；/goal clear 放棄。`;
            }
          } else {
            continuationPlan = {
              turnIndex: result.state.turns_used + 1,
              maxTurns: result.state.max_turns,
              objective: result.state.objective,
              lastReason: result.state.last_reason,
            };
          }
        }
      } catch (err) {
        console.error(`[chat ${chatId}] AB-7b continuation planning failed:`, err);
      }
    } else {
      // Already in a continuation turn — check budget again.
      try {
        const gs = await goalStore.get(config.memoryDir, chatId);
        if (gs && gs.status === "active") {
          const result = await goalStore.incrementTurn(config.memoryDir, chatId, session.buffer ? session.buffer.slice(0, 200) : undefined);
          logEvent("goal_step", { turn: result.state.turns_used, maxTurns: result.state.max_turns, pausedByBudget: result.pausedByBudget, continuation: true }, { chatId, userId: ctx.from?.id });
          if (result.pausedByBudget) {
            const reflection = `Budget exhausted (${result.state.turns_used}/${result.state.max_turns}) without achieving goal. Last output: ${(session.buffer || "").slice(0, 200)}`;
            const retryResult = await goalStore.markReflectionRetry(config.memoryDir, chatId, reflection);
            if (retryResult.ok) {
              console.log(`[chat ${chatId}] goal reflection retry ${retryResult.state.reflection_retries}/${goalStore.GOAL_REFLECTION_MAX} (continuation path)`);
              continuationPlan = {
                turnIndex: 1,
                maxTurns: retryResult.state.max_turns,
                objective: retryResult.state.objective,
                lastReason: `[Reflection retry ${retryResult.state.reflection_retries}/${goalStore.GOAL_REFLECTION_MAX}] Previous attempt failed to achieve the goal. Reflect: what went wrong? Try a different approach.\n${reflection}`,
              };
            } else {
              goalAchievementLine = `\n\n⏸ Goal paused — ${result.state.turns_used}/${result.state.max_turns} turns used, ${result.state.reflection_retries}/${goalStore.GOAL_REFLECTION_MAX} retries exhausted. /goal resume 續跑；/goal clear 放棄。`;
            }
          } else {
            continuationPlan = {
              turnIndex: result.state.turns_used + 1,
              maxTurns: result.state.max_turns,
              objective: result.state.objective,
              lastReason: result.state.last_reason,
            };
          }
        }
      } catch (err) {
        console.error(`[chat ${chatId}] AB-7b continuation re-plan failed:`, err);
      }
    }

    // ─── MoA goal auto-trigger (W9, SPEC-moa-provider) ──────────────────────
    // Post-hoc second opinion during an active goal: fires when the agent
    // explicitly asks for one or reflexion is stuck. Guardrails (max_per_goal,
    // cooldown, reason dedup) live in checkMoaAutoTrigger. Fire-and-forget —
    // the blind review takes tens of seconds; the aggregation prompt goes in
    // as a meta turn (queued by runPrompt if the session is inflight).
    if (!isMeta && !ab7.goalDone && session.buffer) {
      try {
        const gsMoa = await goalStore.get(config.memoryDir, chatId).catch(() => null);
        if (gsMoa && gsMoa.status === "active") {
          const moa = await import("./moa.js");
          const decision = await moa.checkMoaAutoTrigger(chatId, gsMoa, session.buffer);
          if (decision.fire) {
            const replySnapshot = session.buffer.slice(-2000);
            const historySnapshot = [...session.history];
            logEvent("moa_auto_trigger", { reason: decision.reason, preset: decision.preset }, { chatId, userId: ctx.from?.id });
            bot.api.sendMessage(chatId, `🧠 [MoA auto-triggered: ${decision.reason}] 盲審中…`).catch(() => {});
            void (async () => {
              try {
                const result = await moa.runMoaBlindReview({
                  question: `針對 agent 目前的產出給第二意見（goal: ${gsMoa.objective.slice(0, 200)}）：\n${replySnapshot}`,
                  history: historySnapshot,
                  presetName: decision.preset,
                  userId: ctx.from?.id,
                  chatId,
                });
                for (const chunk of moa.formatOpinionsMessage(result).match(/[\s\S]{1,3900}/g) ?? []) {
                  await bot.api.sendMessage(chatId, chunk).catch(() => {});
                }
                if (result.opinions.some((o) => o.status === "ok")) {
                  const s2 = sessions.peek(chatId);
                  if (s2) {
                    const prompt = `[MoA auto-triggered: ${decision.reason}]\n` + moa.buildAggregationPrompt(result);
                    runPrompt(ctx, s2, prompt, { kind: "meta" }).catch(() => {});
                  }
                }
              } catch (err) {
                console.error(`[chat ${chatId}] MoA auto-trigger run failed:`, err);
              }
            })();
          }
        }
      } catch (err) {
        console.error(`[chat ${chatId}] MoA auto-trigger check failed:`, err);
      }
    }

    // ─── RESTART token ──────────────────────────────────────────────────────
    if (!isMeta && ab7.restartToken) {
      const requestedReason = ab7.restartToken.reason;
      if (ab7.goalDone) {
        console.warn(`[chat ${chatId}] RESTART ignored: GOAL_DONE present in same turn (restart reason="${requestedReason}")`);
      } else {
        try {
          const result = await goalStore.markRestart(config.memoryDir, chatId, requestedReason);
          if (result.ok || (!result.ok && (result.code === "no-goal" || result.code === "not-active" || result.code === "empty-reason"))) {
            pendingRestartReason = requestedReason;
            const countLine = result.ok
              ? `🔄 Agent 請求 bridge 重啟 (${result.state.restart_count}/${goalStore.GOAL_RESTART_CAP_PER_GOAL}): ${requestedReason}`
              : `🔄 Agent 請求 bridge 重啟: ${requestedReason}`;
            goalAchievementLine = goalAchievementLine
              ? `${goalAchievementLine}\n\n${countLine}`
              : `\n\n${countLine}`;
            if (continuationPlan) {
              console.log(`[chat ${chatId}] RESTART accepted: dropping pending continuationPlan (turn ${continuationPlan.turnIndex}/${continuationPlan.maxTurns}); post-restart auto-resume will re-fire it`);
              continuationPlan = null;
            }
          } else {
            const warnLine = `⚠️ RESTART 忽略 (${result.code}): ${result.message}`;
            goalAchievementLine = goalAchievementLine
              ? `${goalAchievementLine}\n\n${warnLine}`
              : `\n\n${warnLine}`;
            console.warn(`[chat ${chatId}] RESTART rejected: code=${result.code} reason="${requestedReason}" — ${result.message}`);
          }
        } catch (err) {
          console.error(`[chat ${chatId}] goalStore.markRestart failed:`, err);
          const warnLine = `⚠️ RESTART 忽略:內部錯誤 ${(err as Error).message}`;
          goalAchievementLine = goalAchievementLine
            ? `${goalAchievementLine}\n\n${warnLine}`
            : `\n\n${warnLine}`;
        }
      }
    }


    // ─── Schedule / SendFile / Ask token processing ─────────────────────────
    const sendFilePaths = ab7.sendFiles;
    const scheduleEntries = ab7.scheduleTokens;
    const scheduleReceipts: string[] = [];
    for (const se of scheduleEntries) {
      try {
        const entry = await scheduleStore.add({
          chatId,
          userId: ctx.from?.id ?? chatId,
          runAt: se.runAt,
          prompt: se.prompt,
          recurrence: se.recurrence,
        });
        scheduler.arm(entry);
        const delta = formatRelative(se.runAt - Date.now());
        const recurTag = se.recurrence ? ` [${formatRecurrence(se.recurrence)}]` : "";
        scheduleReceipts.push(
          `⏰ 已排程 ${entry.id}${recurTag}，${delta} 後觸發（${new Date(se.runAt).toLocaleString()}）`,
        );
      } catch (err) {
        console.error(`[chat ${chatId}] schedule token register failed:`, err);
        scheduleReceipts.push(`⏰ 排程建立失敗：${(err as Error).message}`);
      }
    }
    const asks = ab7.askTokens;
    const displayBody = ab7.text;
    const bodyWithReceipts = scheduleReceipts.length
      ? (displayBody ? `${displayBody}\n\n${scheduleReceipts.join("\n")}` : scheduleReceipts.join("\n"))
      : displayBody;
    const bodyWithGoal = goalAchievementLine
      ? bodyWithReceipts + goalAchievementLine
      : bodyWithReceipts;

    if (!bodyWithReceipts) {
      console.warn(
        `[chat ${chatId}] empty-reply diag: stopReason=${stopReason} tools=${session.toolTimeline.length} rawBufferChars=${session.buffer.length} sendFileTokens=${sendFilePaths.length} scheduleTokens=${scheduleEntries.length} askTokens=${asks.length} rateLimitedDuringTurn=${turnHitRateLimit}`,
      );
    }
    const emptyFallbackFinal = () => {
      const parts: string[] = [`stopReason: ${stopReason ?? "unknown"}`];
      if (session.toolTimeline.length > 0) parts.push(`${session.toolTimeline.length} tool calls`);
      if (turnHitRateLimit) parts.push("rate-limited during turn");
      return `(no response — ${parts.join(", ")})`;
    };
    const body = bodyWithGoal || emptyFallbackFinal();
    const askKeyboard = buildAskKeyboard(asks);

    // Context usage
    const agentIn = typeof session.usage?.input_tokens === "number" ? session.usage.input_tokens as number : 0;
    const agentOut = typeof session.usage?.output_tokens === "number" ? session.usage.output_tokens as number : 0;
    const hasAgentUsage = agentIn > 0;
    const totalTok = hasAgentUsage
      ? agentIn + agentOut
      : (() => {
          const userText = session.history.filter(h => h.role === "user").map(h => h.text).join("");
          const agentText = session.history.filter(h => h.role === "assistant").map(h => h.text).join("");
          return estimateTokens(session.memoryPreamble) + estimateTokens(userText) + estimateTokens(agentText);
        })();
    const usageLine = hasAgentUsage
      ? `\n\n— ctx ~${totalTok}/${config.contextWindowTokens} tok (${pct(totalTok)}) • in ${agentIn} · out ${agentOut}`
      : (() => {
          const userText = session.history.filter(h => h.role === "user").map(h => h.text).join("");
          const agentText = session.history.filter(h => h.role === "assistant").map(h => h.text).join("");
          const preTok = estimateTokens(session.memoryPreamble);
          const inTok = estimateTokens(userText);
          const outTok = estimateTokens(agentText);
          const share = (n: number) =>
            totalTok > 0 ? ((n / totalTok) * 100).toFixed(0) + "%" : "0%";
          return `\n\n— ctx ~${totalTok}/${config.contextWindowTokens} tok (${pct(totalTok)}) ` +
            `• preamble ${preTok} (${share(preTok)}) · user ${inTok} (${share(inTok)}) · agent ${outTok} (${share(outTok)})`;
        })();
    const stopHint = (() => {
      if (!stopReason) return "";
      if (stopReason === "end_turn" || stopReason === "stop") return "";
      return `\n\n⚠️ stream ended: ${stopReason}`;
    })();
    const suffix = stopHint + usageLine;
    const full = (replyHeader ? `${replyHeader}\n\n` : "") + toolsPrefix + body;

    if (isSilentMeta) {
      console.log(`[chat ${chatId}] silent meta prompt completed (stopReason=${stopReason ?? "unknown"}, tools=${session.toolTimeline.length}, bufferChars=${session.buffer.length})`);
      return;
    }


    // ─── Relay reply path (headless) ────────────────────────────────────────
    if (relayReplyTo) {
      for (const rt of relayTokens) {
        sendRelay(rt.target, rt.text).catch((err) =>
          console.error(`[chat ${chatId}] sendRelay to ${rt.target} failed:`, err));
      }
      for (const rf of relayFileTokens) {
        addRelayTaskOutput(rf.target, rf.path).catch((err) =>
          console.error(`[chat ${chatId}] addRelayTaskOutput to ${rf.target} failed:`, err));
        sendRelayFile(rf.target, rf.path, "[RELAY_OUTPUT]").catch((err) =>
          console.error(`[chat ${chatId}] sendRelayFile to ${rf.target} failed:`, err));
      }
      for (const rd of relayDelegateTokens) {
        upsertRelayTask({
          id: rd.payload.id,
          peer: rd.target,
          direction: "outgoing",
          status: "active",
          goal: rd.payload.goal,
          context: rd.payload.context,
          ownerChatId: config.allowedUserIds[0] ?? chatId,
          relayChatId: chatId,
        }).catch((err) =>
          console.error(`[chat ${chatId}] upsertRelayTask delegate to ${rd.target} failed:`, err));
        sendRelayDelegate(rd.target, rd.payload).catch((err) =>
          console.error(`[chat ${chatId}] sendRelayDelegate to ${rd.target} failed:`, err));
      }
      for (const rr of relayResultTokens) {
        upsertRelayTask({
          id: rr.payload.id,
          peer: rr.target,
          direction: "incoming",
          status: rr.payload.status === "done" ? "done" : rr.payload.status === "timeout" ? "timeout" : "failed",
          resultSummary: rr.payload.summary,
          ownerChatId: config.allowedUserIds[0] ?? chatId,
          relayChatId: chatId,
        }).catch((err) =>
          console.error(`[chat ${chatId}] upsertRelayTask result to ${rr.target} failed:`, err));
        sendRelayResult(rr.target, rr.payload).catch((err) =>
          console.error(`[chat ${chatId}] sendRelayResult to ${rr.target} failed:`, err));
        getRelayLoopGuard()?.markDone(rr.target);
      }
      const sentExplicitReply = relayTokens.some((rt) => rt.target === relayReplyTo) ||
        relayResultTokens.some((rr) => rr.target === relayReplyTo);
      const shouldSendAutoReply = !sentExplicitReply && full.trim() !== "";
      if (shouldSendAutoReply) {
        sendRelay(relayReplyTo, full).catch((err) =>
          console.error(`[chat ${chatId}] auto relay reply to ${relayReplyTo} failed:`, err));
      }
      console.log(
        `[chat ${chatId}] relay reply delivered headlessly to ${relayReplyTo} ` +
          `(stopReason=${stopReason ?? "unknown"}, bufferChars=${session.buffer.length}` +
          `${relayDone ? ", RELAY_DONE" : ""}, autoReply=${shouldSendAutoReply})`,
      );

      if (relayDone) {
        const peer = relayReplyTo;
        const privateChatId = config.allowedUserIds[0] ?? 0;
        if (privateChatId) {
          bot.api.sendMessage(privateChatId, `✅ 與「${peer}」的 relay 對話結束`).catch(() => {});
        }
        setTimeout(() => {
          const summaryPrompt =
            `[系統] 你剛才與「${peer}」的 relay 對話已結束。` +
            `請用一句話摘要這次 relay 對話的重點，然後呼叫 remember() 存下來。` +
            `格式範例：remember("[relay ${peer}] …摘要內容…")。` +
            `不需要回覆其他內容。`;
          runPrompt(ctx, session, summaryPrompt, { kind: "meta", silent: true }).catch((err) => {
            console.error(`[chat ${chatId}] relay summary meta prompt failed:`, err);
          });
        }, GOAL_CONTINUATION_DELAY_MS);
      }
      return;
    }


    // ─── Telegram message delivery ──────────────────────────────────────────
    if (!placeholder && !useDraftMode) {
      throw new Error("visible Telegram reply is missing a placeholder");
    }
    const chunks = splitForTelegram(full);
    const pageTag = (i: number) =>
      chunks.length > 1 ? `(${i + 1}/${chunks.length})\n` : "";

    const pace = () => new Promise<void>((r) => setTimeout(r, 1100));
    let chunksSent = 0;
    let chunksQueued = 0;
    const sendOrQueue = async (text: string, extra?: Record<string, unknown>) => {
      try {
        const msg = await ctx.reply(text, extra);
        chunksSent++;
        return msg;
      } catch (err) {
        console.error(`[chat ${chatId}] chunk send failed, queueing for replay:`, err);
        queuePendingMessage(chatId, text);
        chunksQueued++;
        return undefined;
      }
    };

    const richSendOrQueue = async (text: string, extra?: Record<string, unknown>) => {
      try {
        if (config.tgRichStreamEnabled) {
          const richMsg = await trySendRichMessage(ctx.api, chatId, text, extra ?? {});
          if (richMsg) { chunksSent++; return richMsg; }
        }
        const msg = await ctx.reply(text, extra);
        chunksSent++;
        return msg;
      } catch (err) {
        console.error(`[chat ${chatId}] chunk send failed, queueing for replay:`, err);
        queuePendingMessage(chatId, text);
        chunksQueued++;
        return undefined;
      }
    };

    let finalMessageId: number | undefined;
    if (chunks.length === 1) {
      const finalExtra: Record<string, unknown> = {
        ...(askKeyboard ? { reply_markup: askKeyboard } : {}),
        ...(replyToId ? { reply_parameters: { message_id: replyToId } } : {}),
      };
      try {
        // Draft path：sendRichMessage 持久化（draft 自動消失）
        if (useDraftMode) {
          const richMsg = await trySendRichMessage(ctx.api, chatId, chunks[0] + suffix, finalExtra);
          if (richMsg) {
            finalMessageId = richMsg.message_id;
            chunksSent++;
          } else {
            // rich 不支援 → plain sendMessage
            const msg = await ctx.api.sendMessage(chatId, chunks[0] + suffix, finalExtra);
            finalMessageId = msg.message_id;
            chunksSent++;
          }
        }
        // Placeholder path（非 draft 或 draft final 失敗）
        if (finalMessageId === undefined && placeholder) {
          if (config.tgRichStreamEnabled) {
            const richEdited = await tryEditRichMessageDraft(
              ctx.api,
              chatId,
              placeholder.message_id,
              chunks[0] + suffix,
              askKeyboard ? { reply_markup: askKeyboard } : {},
            );
            if (richEdited) {
              finalMessageId = placeholder.message_id;
              chunksSent++;
            }
          }
          if (finalMessageId === undefined) {
            await ctx.api.editMessageText(
              chatId,
              placeholder.message_id,
              chunks[0] + suffix,
              askKeyboard ? { reply_markup: askKeyboard } : {},
            );
            finalMessageId = placeholder.message_id;
            chunksSent++;
          }
        }
      } catch (err) {
        console.error(`[chat ${chatId}] final edit failed, attempting direct send to preserve keyboard:`, err);
        try {
          const msg = await ctx.api.sendMessage(
            chatId,
            chunks[0] + suffix,
            askKeyboard ? { reply_markup: askKeyboard } : {},
          );
          finalMessageId = msg.message_id;
          chunksSent++;
        } catch (err2) {
          console.error(`[chat ${chatId}] direct-send fallback also failed, queueing (keyboard will be dropped):`, err2);
          queuePendingMessage(chatId, chunks[0] + suffix);
          chunksQueued++;
        }
      }
    } else {
      // Multi-chunk：第一 chunk 用 sendRichMessage（draft 消失）或 editMessageText（placeholder）
      try {
        if (useDraftMode) {
          const richMsg = await trySendRichMessage(ctx.api, chatId, pageTag(0) + chunks[0],
            replyToId ? { reply_parameters: { message_id: replyToId } } : {});
          if (richMsg) { chunksSent++; }
          else {
            const msg = await ctx.api.sendMessage(chatId, pageTag(0) + chunks[0]);
            chunksSent++;
          }
        } else if (placeholder) {
          if (config.tgRichStreamEnabled) {
            const richEdited = await tryEditRichMessageDraft(ctx.api, chatId, placeholder.message_id, pageTag(0) + chunks[0]);
            if (richEdited) { chunksSent++; }
            else {
              await ctx.api.editMessageText(chatId, placeholder.message_id, pageTag(0) + chunks[0]);
              chunksSent++;
            }
          } else {
            await ctx.api.editMessageText(chatId, placeholder.message_id, pageTag(0) + chunks[0]);
            chunksSent++;
          }
        }
      } catch (err) {
        console.error(`[chat ${chatId}] first-chunk edit failed, queueing:`, err);
        queuePendingMessage(chatId, pageTag(0) + chunks[0]);
        chunksQueued++;
      }
      for (let i = 1; i < chunks.length - 1; i++) {
        await pace();
        await richSendOrQueue(pageTag(i) + chunks[i]);
      }
      await pace();
      const last = chunks.length - 1;
      const sent = await richSendOrQueue(
        pageTag(last) + chunks[last] + suffix,
        askKeyboard ? { reply_markup: askKeyboard } : undefined
      );
      if (sent) finalMessageId = sent.message_id;
    }
    console.log(
      `[chat ${chatId}] delivered ${chunksSent}/${chunks.length} chunks ` +
        `(stopReason=${stopReason ?? "unknown"}, bufferChars=${session.buffer.length})` +
        (chunksQueued > 0 ? `, ${chunksQueued} queued for replay` : ""),
    );
    if (askKeyboard && finalMessageId !== undefined) {
      askRegistry.set(finalMessageId, asks);
    }

    // Deliver files
    try {
      await sendFilesByPaths(ctx, sendFilePaths);
    } catch (err) {
      console.error(`[chat ${chatId}] sendFilesByPaths failed:`, err);
    }


    // ─── Stickers ──────────────────────────────────────────────────────────
    if (ab7.stickerEmotions.length === 0 && isEmbedModelReady()) {
      try {
        const autoEmotion = await autoSelectSticker(ab7.text);
        if (autoEmotion) ab7.stickerEmotions.push(autoEmotion);
      } catch { /* best-effort */ }
    }
    for (const emotion of ab7.stickerEmotions) {
      const fileId = STICKER_MAP[emotion];
      if (!fileId) continue;
      try {
        await ctx.replyWithSticker(fileId);
        console.log(`[chat ${chatId}] STICKER: sent ${emotion}`);
      } catch (err) {
        console.warn(`[chat ${chatId}] STICKER: failed ${emotion} — ${(err as Error).message}`);
      }
    }

    // ─── Relay tokens (user-facing path) ─────────────────────────────────
    if (!relayDone) {
      if (relayTokens.length > 0) console.log(`[chat ${chatId}] relay tokens parsed: ${relayTokens.map(t => t.target).join(", ")}`);
      for (const rt of relayTokens) {
        if (!relayReplyTo) getRelayLoopGuard()?.reopen(rt.target);
        sendRelay(rt.target, rt.text).catch((err) =>
          console.error(`[chat ${chatId}] sendRelay to ${rt.target} failed:`, err));
      }
      for (const rf of relayFileTokens) {
        sendRelayFile(rf.target, rf.path).catch((err) =>
          console.error(`[chat ${chatId}] sendRelayFile to ${rf.target} failed:`, err));
      }
      for (const rd of relayDelegateTokens) {
        if (isLocalSpecialist(rd.target)) {
          console.log(`[chat ${chatId}] dispatching to local specialist "${rd.target}" (id=${rd.payload.id})`);
          saveDelegationContext(chatId, rd.payload.id, session).catch((err) =>
            console.error(`[chat ${chatId}] saveDelegationContext failed:`, err));
          dispatchToSpecialist(rd.target, rd.payload, ctx.from?.id).then(async (_result) => {
            let result = _result;
            console.log(`[chat ${chatId}] specialist "${rd.target}" returned: ${result.payload.status}, summary length=${result.payload.summary?.length ?? 0}`);
            saveArtifact(rd.payload.id, rd.target, rd.payload.goal, result.payload.status as any, result.payload.summary, result.rawOutput).catch((e) => console.warn(`[chat ${chatId}] saveArtifact failed:`, e));

            // Verifier gate: check specialist output quality
            const vr = await verifySpecialistOutput(rd.payload.goal, result.rawOutput);
            logEvent("specialist_done", { taskId: rd.payload.id, target: rd.target, verifier: vr.pass ? "PASS" : "NEEDS_FIX", source: vr.source, issues: vr.issues?.slice(0, 300) }, { chatId });
            let verifierNote = "";
            if (!vr.pass && vr.issues) {
              console.log(`[chat ${chatId}] verifier NEEDS_FIX (${vr.source}): ${vr.issues.slice(0, 100)}`);
              // Retry once with feedback
              const retryPayload = { ...rd.payload, goal: buildRetryPrompt(rd.payload.goal, vr.issues) };
              try {
                const retry = await dispatchToSpecialist(rd.target, retryPayload, ctx.from?.id);
                const vr2 = await verifySpecialistOutput(rd.payload.goal, retry.rawOutput);
                if (vr2.pass) {
                  result = retry;
                } else {
                  result = retry;
                  verifierNote = `\n⚠️ Verifier 標記問題：${vr2.issues ?? vr.issues}`;
                }
              } catch { verifierNote = `\n⚠️ Verifier 標記問題：${vr.issues}`; }
            }

            const delegationCtx = await loadDelegationContext(rd.payload.id);
            const metaPrompt =
              delegationCtx +
              `[系統] Specialist "${rd.target}" 委派結果回傳\n` +
              `Status: ${result.payload.status}\n` +
              `Summary:\n${result.payload.summary}${verifierNote}\n` +
              `[End specialist result]\n\n` +
              `請根據委派結果繼續回覆使用者。`;
            const userId = config.allowedUserIds[0] ?? chatId;
            const fakeCtx = {
              chat: { id: chatId, type: "private" as const },
              from: { id: userId, is_bot: false, first_name: rd.target },
              message: { message_id: 0, date: 0, chat: { id: chatId, type: "private" as const }, text: metaPrompt },
              api: bot.api,
              reply: (text: string, extra?: any) => bot.api.sendMessage(chatId, text, extra),
            } as unknown as Context;
            const s = await sessions.get(chatId, userId);
            console.log(`[chat ${chatId}] specialist result injection: session.inflight=${s.inflight}, client.isClosed=${s.client.isClosed}`);
            if (isDuplicateResult(chatId, result.payload.summary ?? "")) {
              console.log(`[chat ${chatId}] specialist result skipped (dedup hit)`);
              return;
            }
            try {
              await runPrompt(fakeCtx, s, metaPrompt, { kind: "meta" });
              console.log(`[chat ${chatId}] specialist result injection: runPrompt completed`);
            } catch (runErr) {
              console.error(`[chat ${chatId}] specialist result injection: runPrompt threw:`, runErr);
            }
          }).catch((err) => {
            console.error(`[chat ${chatId}] specialist dispatch failed:`, err);
          });
        } else {
          if (!relayReplyTo) getRelayLoopGuard()?.reopen(rd.target);
          registerTask({
            taskId: rd.payload.id,
            type: "relay_delegate",
            peer: rd.target,
            goal: rd.payload.goal.slice(0, 100),
          });
          upsertRelayTask({
            id: rd.payload.id,
            peer: rd.target,
            direction: "outgoing",
            status: "active",
            goal: rd.payload.goal,
            context: rd.payload.context,
            ownerChatId: config.allowedUserIds[0] ?? chatId,
            relayChatId: chatId,
            attachmentPath: session._lastUploadPath,
          }).catch((err) =>
            console.error(`[chat ${chatId}] upsertRelayTask delegate to ${rd.target} failed:`, err));
          if (session._lastUploadPath) {
            const attachmentPath = session._lastUploadPath;
            session._lastUploadPath = undefined;
            const caption = `${DELEGATE_PREFIX} ${JSON.stringify(rd.payload)}`;
            if (caption.length <= 1000) {
              sendRelayFile(rd.target, attachmentPath, caption).catch((err) =>
                console.error(`[chat ${chatId}] sendRelayFile (delegate attachment) to ${rd.target} failed:`, err));
            } else {
              sendRelayDelegate(rd.target, rd.payload)
                .then(() => sendRelayFile(rd.target, attachmentPath))
                .catch((err) =>
                  console.error(`[chat ${chatId}] relay delegate + attachment fallback to ${rd.target} failed:`, err));
            }
          } else {
            sendRelayDelegate(rd.target, rd.payload).catch((err) =>
              console.error(`[chat ${chatId}] sendRelayDelegate to ${rd.target} failed:`, err));
          }
          if (!relayReplyTo) {
            saveDelegationContext(chatId, rd.payload.id, session).catch((err) =>
              console.error(`[chat ${chatId}] saveDelegationContext failed:`, err));
          }
        }
      }
      for (const rr of relayResultTokens) {
        upsertRelayTask({
          id: rr.payload.id,
          peer: rr.target,
          direction: "incoming",
          status: rr.payload.status === "done" ? "done" : rr.payload.status === "timeout" ? "timeout" : "failed",
          resultSummary: rr.payload.summary,
          ownerChatId: config.allowedUserIds[0] ?? chatId,
          relayChatId: chatId,
        }).catch((err) =>
          console.error(`[chat ${chatId}] upsertRelayTask result to ${rr.target} failed:`, err));
        sendRelayResult(rr.target, rr.payload).catch((err) =>
          console.error(`[chat ${chatId}] sendRelayResult to ${rr.target} failed:`, err));
        getRelayLoopGuard()?.markDone(rr.target);
      }
      if (relayReplyTo && !relayTokens.some((rt) => rt.target === relayReplyTo)) {
        sendRelay(relayReplyTo, body).catch((err) =>
          console.error(`[chat ${chatId}] auto relay reply to ${relayReplyTo} failed:`, err));
      }
    }


    // ─── Parallel Delegate Dispatch ────────────────────────────────────────
    if (parallelDelegateTasks.length > 0) {
      const validTasks = parallelDelegateTasks.filter((t) => isLocalSpecialist(t.target));
      const invalidTasks = parallelDelegateTasks.filter((t) => !isLocalSpecialist(t.target));
      for (const inv of invalidTasks) {
        console.warn(`[chat ${chatId}] PARALLEL_DELEGATE unknown specialist: ${inv.target}`);
      }
      if (validTasks.length > 0) {
        console.log(`[chat ${chatId}] dispatching ${validTasks.length} parallel delegate(s): ${validTasks.map((t) => `${t.target}:${t.taskId}`).join(", ")}`);
        dispatchParallel(validTasks, ctx.from?.id).then(async (results) => {
          console.log(`[chat ${chatId}] parallel dispatch complete: ${results.map((r) => `${r.taskId}=${r.status}`).join(", ")}`);
          for (const r of results) {
            const task = validTasks.find((t) => t.taskId === r.taskId);
            saveArtifact(r.taskId, r.target, task?.payload.goal ?? "", r.status, r.summary, r.rawOutput).catch((e) => console.warn(`[chat ${chatId}] saveArtifact failed:`, e));
          }
          const lines = results.map((r) => {
            const statusIcon = r.status === "done" ? "✅" : r.status === "timeout" ? "⏱️" : "❌";
            return `[PARALLEL_RESULT:${r.taskId}] ${statusIcon} (${r.target}, ${r.status})\n${r.summary}`;
          });
          const metaPrompt =
            `[系統] 並行委派結果回傳（${results.length} 個任務全部完成）\n\n` +
            lines.join("\n\n---\n\n") + "\n\n" +
            `[End parallel results]\n\n` +
            `請根據以上結果繼續回覆使用者。`;
          const userId = config.allowedUserIds[0] ?? chatId;
          const fakeCtx = {
            chat: { id: chatId, type: "private" as const },
            from: { id: userId, is_bot: false, first_name: "parallel" },
            message: { message_id: 0, date: 0, chat: { id: chatId, type: "private" as const }, text: metaPrompt },
            api: bot.api,
            reply: (text: string, extra?: any) => bot.api.sendMessage(chatId, text, extra),
          } as unknown as Context;
          const s = await sessions.get(chatId, userId);
          if (isDuplicateResult(chatId, metaPrompt)) {
            console.log(`[chat ${chatId}] parallel result skipped (dedup hit)`);
            return;
          }
          if (s.inflight) {
            console.log(`[chat ${chatId}] parallel result queued (session inflight)`);
            s._pendingMetaQueue.push({ ctx: fakeCtx, prompt: metaPrompt, opts: { kind: "meta" } });
          } else {
            try {
              await runPrompt(fakeCtx, s, metaPrompt, { kind: "meta" });
            } catch (err) {
              console.error(`[chat ${chatId}] parallel result injection failed:`, err);
            }
          }
        }).catch((err) => {
          console.error(`[chat ${chatId}] parallel dispatch failed:`, err);
        });
      }
    }

    // Skill propose
    if (!isMeta && ab7.skillPropose) {
      const { name, reason } = ab7.skillPropose;
      const kb = new InlineKeyboard()
        .text("✅ 寫成 skill", `SP:${name}:yes`)
        .text("❌ 不用", `SP:${name}:no`);
      await ctx.reply(
        `💡 建議寫成 skill：\`${name}\`\n${reason}`,
        { parse_mode: "Markdown", reply_markup: kb },
      );
    }

    // MoA plan token (Phase 2, W15/W16): parse the aggregator's plan JSON,
    // store it pending, and render the confirm keyboard. Malformed JSON gets
    // ONE re-emit retry (meta turn) before giving up — deterministic repair
    // already happened inside parseMoaPlan.
    if (ab7.moaPlan) {
      try {
        const moaPlanMod = await import("./moa-plan.js");
        const { getSpecialists } = await import("./specialist.js");
        const known = getSpecialists().map((s) => s.name);
        const parsed = moaPlanMod.parseMoaPlan(ab7.moaPlan.raw, known);
        if (parsed.ok) {
          moaPlanMod.clearPlanParseRetry(chatId);
          const task = moaPlanMod.consumePlanTaskHint(chatId) ?? parsed.plan.summary;
          moaPlanMod.setPendingPlan(chatId, {
            plan: parsed.plan,
            task,
            status: "awaiting-confirm",
            createdAt: Date.now(),
          });
          const warnLines = parsed.warnings.length ? `\n⚠️ ${parsed.warnings.join("\n⚠️ ")}` : "";
          await bot.api.sendMessage(chatId, moaPlanMod.renderPlanMessage(parsed.plan) + warnLines, {
            reply_markup: moaPlanMod.buildPlanConfirmKeyboard(),
          }).catch((err) => console.error(`[chat ${chatId}] MOA_PLAN confirm send failed:`, err));
        } else {
          const tries = moaPlanMod.bumpPlanParseRetry(chatId);
          if (tries <= 1) {
            const retryPrompt =
              `[系統] 你剛才的 <<MOA_PLAN:...>> token 無法解析：${parsed.error}。\n` +
              `請重新輸出一次 MOA_PLAN token：單行 compact JSON、裸寫不包 code block、` +
              `格式 {"plan":{"summary":"...","steps":[{"id":"s1","task":"...","specialist":"general","depends_on":[]}]}}。`;
            runPrompt(ctx, session, retryPrompt, { kind: "meta" }).catch(() => {});
          } else {
            moaPlanMod.clearPlanParseRetry(chatId);
            await bot.api.sendMessage(chatId, `❌ MoA 計畫解析失敗（${parsed.error}），已放棄。可重新 /moa plan。`).catch(() => {});
          }
        }
      } catch (err) {
        console.error(`[chat ${chatId}] MOA_PLAN handling failed:`, err);
      }
    }

    // Wiki auto-trigger
    if (!isMeta && ab7.wikiQuery) {
      const { slug, summary } = ab7.wikiQuery;
      const excerpt = body.length > 2000 ? body.slice(0, 2000) + "\n…(truncated)" : body;
      const prompt =
        `[系統] 你剛才的回覆被標記為值得存入 wiki（摘要：${summary}）。\n` +
        `請整理成一頁 wiki query page，存到 ${MEMORY_DIR}/wiki/queries/${slug}.md。\n\n` +
        `規則：\n` +
        `- 如果 ${MEMORY_DIR}/wiki/queries/${slug}.md 已存在，更新內容並 bump frontmatter updated 日期（不要重建）\n` +
        `- 遵循 ${MEMORY_DIR}/wiki/SCHEMA.md 的 frontmatter 格式（type: query）\n` +
        `- title 用：${summary}\n` +
        `- 內容是結構化段落（不是原文照貼），≤200 行\n` +
        `- 至少 1 個 [[wikilink]] 連到其他 wiki 頁面\n` +
        `- 寫完後更新 ${MEMORY_DIR}/wiki/index.md（加一行 wikilink + 摘要；已存在則不重複加）\n` +
        `- 用繁體中文\n\n` +
        `原始回覆內容：\n---\n${excerpt}\n---`;
      setTimeout(() => {
        runPrompt(ctx, session, prompt, { kind: "meta" })
          .then(() => applyAutoWikilink(slug))
          .catch(
            (err) => console.error(`[chat ${chatId}] WIKI_QUERY failed:`, err),
          );
      }, GOAL_CONTINUATION_DELAY_MS);
    }

    // Wiki auto-save 候選：agent 沒自己加 WIKI_QUERY token 時，自動評估這輪
    // 回覆是否值得存 wiki。只在使用者直接提問的回合跑（meta / continuation /
    // relay 不算）。這裡只記錄候選到 wiki-auto-save-candidates.jsonl，實際
    // 產出 wiki page 由 /wikisync（含 /dream 的 wikisync 步驟）消費。
    if (mode.kind === "user" && !ab7.wikiQuery) {
      try {
        const autoSaveEval = evaluateForAutoSave(text, body);
        if (autoSaveEval.shouldSave) {
          const rec = recordAutoSaveCandidate(text, body, autoSaveEval);
          if (rec) console.log(`[chat ${chatId}] wiki auto-save candidate recorded: ${rec.slug}`);
        }
      } catch (err) {
        // 旁路訊號，絕不影響主回覆路徑
        console.error(`[chat ${chatId}] wiki auto-save evaluation failed:`, err);
      }
    }

    // Specialist proxy
    if (!isMeta && ab7.specialistProxy && isLocalSpecialist(ab7.specialistProxy.name)) {
      const { name, message } = ab7.specialistProxy;
      appendRoutingLog({ message: message.slice(0, 200), routedTo: name, method: "manual" });
      startProxy(chatId, name);
      const prefix = `🤖 *[${name}]*\n`;
      bot.api.sendMessage(chatId, `${prefix}Thinking… ▍`, { parse_mode: "Markdown" })
        .catch(() => bot.api.sendMessage(chatId, `🤖 [${name}]\nThinking… ▍`))
        .then(async (proxyPlaceholder) => {
          if (!proxyPlaceholder) return;
          let proxyLastEditAt = 0;
          let proxyLastRendered = "";
          let proxyEditTimer: NodeJS.Timeout | null = null;
          const proxyEditNow = (proxyBody: string) => {
            if (proxyBody === proxyLastRendered) return;
            proxyLastRendered = proxyBody;
            proxyLastEditAt = Date.now();
            const frame = `${prefix}${proxyBody.length > TG_MAX ? "…" + proxyBody.slice(-TG_MAX) : proxyBody} ▍`;
            bot.api.editMessageText(chatId, proxyPlaceholder.message_id, frame, { parse_mode: "Markdown" })
              .catch(() => bot.api.editMessageText(chatId, proxyPlaceholder.message_id, `🤖 [${name}]\n${proxyBody} ▍`).catch(() => {}));
          };
          const onChunk = (currentOutput: string) => {
            const stripped2 = stripMemoryTokens(currentOutput).replace(/<<PROXY_DONE>>/gi, "").trim();
            if (!stripped2) return;
            const elapsed = Date.now() - proxyLastEditAt;
            if (elapsed >= STREAM_EDIT_INTERVAL_MS) {
              proxyEditNow(stripped2);
            } else if (!proxyEditTimer) {
              proxyEditTimer = setTimeout(() => {
                proxyEditTimer = null;
                const latest = stripMemoryTokens(currentOutput).replace(/<<PROXY_DONE>>/gi, "").trim();
                if (latest) proxyEditNow(latest);
              }, STREAM_EDIT_INTERVAL_MS - elapsed);
            }
          };
          try {
            const { output, proxyDone } = await promptProxy(chatId, message, onChunk, ctx.from?.id);
            if (proxyEditTimer) { clearTimeout(proxyEditTimer); proxyEditTimer = null; }
            extractMemoryTokensFromProxy(output, ctx.from?.id ?? chatId, name);
            const display = stripMemoryTokens(output).trim();
            const proxyStats2 = getProxyStats(chatId);
            const proxyUsage2 = (() => {
              if (!proxyStats2) return "";
              const inTok = Math.ceil(proxyStats2.charsIn / 4);
              const outTok = Math.ceil(proxyStats2.charsOut / 4);
              const totalTok2 = inTok + outTok;
              const limit = config.contextWindowTokens;
              const pctStr = limit ? ((totalTok2 / limit) * 100).toFixed(1) + "%" : "";
              return `\n\n— ctx ~${totalTok2}/${limit} tok (${pctStr}) • in ${inTok} · out ${outTok}`;
            })();
            if (display) {
              const final = `${prefix}${display.length > TG_MAX ? "…" + display.slice(-TG_MAX) : display}${proxyUsage2}`;
              await bot.api.editMessageText(chatId, proxyPlaceholder.message_id, final, { parse_mode: "Markdown" })
                .catch(() => bot.api.editMessageText(chatId, proxyPlaceholder.message_id, `🤖 [${name}]\n${display}${proxyUsage2}`).catch(() => {}));
            } else {
              await bot.api.editMessageText(chatId, proxyPlaceholder.message_id, `${prefix}(no response)`, { parse_mode: "Markdown" }).catch(() => {});
            }
            if (proxyDone) {
              const proxySession = endProxy(chatId);
              await bot.api.sendMessage(chatId, `✅ Specialist "${name}" 完成，已切回主 agent。`).catch(() => {});
              if (proxySession) {
                const summary2 = buildProxySummary(proxySession);
                const userId = ctx.from?.id ?? chatId;
                const s2 = await sessions.get(chatId, userId);
                runPrompt(ctx, s2, summary2, { kind: "meta" }).catch(() => {});
              }
            }
          } catch (err) {
            if (proxyEditTimer) { clearTimeout(proxyEditTimer); proxyEditTimer = null; }
            console.error(`[chat ${chatId}] specialist proxy initial prompt failed:`, err);
            bot.api.editMessageText(chatId, proxyPlaceholder.message_id, `⚠️ Specialist "${name}" 初始回覆失敗：${(err as Error).message}`).catch(() => {});
            endProxy(chatId);
          }
        });
    }

    // Hoist <<CONTINUE>> flag
    if (!isMeta && ab7.continueToken) continueTokenFired = true;
    petState("done");
    const petSummary = (session.buffer || "").replace(/<<[^>]+>>/g, "").trim().slice(0, 80);
    if (petSummary) petEmit({ type: "reply", text: petSummary });


  } catch (err) {
    const e = err as Error & { code?: number; data?: unknown };
    petState("error", e.message?.slice(0, 60));
    console.error(
      `[chat ${chatId}] prompt failed:`,
      e.code !== undefined ? `code=${e.code}` : "",
      e.message,
      e.data !== undefined ? `data=${JSON.stringify(e.data)}` : "",
      session.stderrTail ? `\nstderr:\n${session.stderrTail}` : ""
    );
    let msg = `Error: ${e.message}`;
    if (e.code === -32603) {
      const tail = session.stderrTail.trim();
      if (/prompt already in progress/i.test(e.message)) {
        msg =
          "⏳ 上一個回合還在進行中，kiro-cli 拒絕了這次的請求。\n" +
          "請等它結束，或先用 /cancel 取消再重試。";
      } else if (tail) {
        const snippet = tail.length > 500 ? "…" + tail.slice(-500) : tail;
        msg += `\n\nAgent stderr:\n${snippet}`;
      } else {
        msg +=
          "\n\nThis is a JSON-RPC internal error from the ACP agent. " +
          "Common causes: kiro-cli not logged in, credentials expired, " +
          "or the model call failed. Try running `kiro-cli` manually to " +
          "confirm it works, or re-run the bridge with DEBUG_ACP=1 for " +
          "full agent logs.";
      }
    }
    // 額度用盡 / 限流錯誤 → 附上 /model 切換提示（ACP 的額度訊息常在 stderr）
    const hint = quotaHint(`${e.message ?? ""}\n${session.stderrTail ?? ""}`);
    if (hint) msg += `\n\n${hint}`;
    if (relayReplyTo) {
      sendRelay(relayReplyTo, msg).catch((err2) =>
        console.error(`[chat ${chatId}] relay error notice to ${relayReplyTo} failed:`, err2));
      return;
    }
    if (placeholder) {
      try {
        await ctx.api.editMessageText(chatId, placeholder.message_id, msg);
      } catch {
        await ctx.reply(msg);
      }
    } else {
      // Draft mode 或無 placeholder — 直接發新訊息（draft 會在 TTL 後自動消失）
      await ctx.reply(msg);
    }
  } finally {
    if (editTimer) {
      clearTimeout(editTimer);
      editTimer = null;
    }
    unregisterRecovery();
    session.onUpdate = undefined;
    session.inflight = false;
    sessions.clearInactivityTimer(session);
    if (session._pendingMetaQueue.length > 0) {
      const queued = session._pendingMetaQueue.splice(0);
      console.log(`[chat ${chatId}] draining ${queued.length} pending meta prompt(s)`);
      setTimeout(async () => {
        for (const item of queued) {
          try {
            await runPrompt(item.ctx as Context, session, item.prompt, item.opts as any);
          } catch (err) {
            console.error(`[chat ${chatId}] pending meta drain failed:`, err);
          }
        }
      }, 500);
    }
  }

  // Post-finally: RESTART takes priority
  if (pendingRestartReason !== null) {
    if (continuationPlan !== null) {
      console.warn(`[chat ${chatId}] RESTART + continuationPlan both present; clearing continuationPlan`);
      continuationPlan = null;
    }
    console.log(`[chat ${chatId}] RESTART accepted; triggering shutdown (reason="${pendingRestartReason}")`);
    handleRestart(ctx, { reason: pendingRestartReason }).catch((err) => {
      console.error(`[chat ${chatId}] handleRestart failed:`, err);
    });
    return;
  }

  // AB-7b: schedule next continuation turn
  if (continuationPlan) {
    const planSnapshot = continuationPlan;
    cancelPendingContinuation(chatId);
    const timer = setTimeout(() => {
      pendingContinuations.delete(chatId);
      const continuationPrompt =
        `[bridge continuation — do not reply to this literally, just continue working toward the goal]\n\n` +
        `Continue toward your standing goal (turn ${planSnapshot.turnIndex}/${planSnapshot.maxTurns}).\n` +
        `Objective: ${planSnapshot.objective}` +
        (planSnapshot.lastReason
          ? `\nPrevious turn preview: ${planSnapshot.lastReason}`
          : "");
      runPrompt(ctx, session, continuationPrompt, {
        kind: "continuation",
        context: planSnapshot,
      }).catch((err) => {
        console.error(`[chat ${chatId}] continuation runPrompt failed:`, err);
      });
    }, GOAL_CONTINUATION_DELAY_MS);
    pendingContinuations.set(chatId, timer);
  }

  // <<CONTINUE>> token
  if (!continuationPlan && !pendingRestartReason && continueTokenFired) {
    cancelPendingContinuation(chatId);
    const timer = setTimeout(() => {
      pendingContinuations.delete(chatId);
      runPrompt(ctx, session, "[bridge continuation — continue where you left off]", {
        kind: "continuation",
        context: { turnIndex: 1, maxTurns: 1, objective: "continue", lastReason: null },
      }).catch((err) => {
        console.error(`[chat ${chatId}] CONTINUE runPrompt failed:`, err);
      });
    }, GOAL_CONTINUATION_DELAY_MS);
    pendingContinuations.set(chatId, timer);
    console.log(`[chat ${chatId}] <<CONTINUE>> token: scheduling follow-up turn`);
  }
}

